// HasConfig applies the HasEdge predicate on the "config" edge.
func HasConfig() predicate.UpstreamKeyRateSnapshot {
	return predicate.UpstreamKeyRateSnapshot(func(s *sql.Selector) {
		step := sqlgraph.NewStep(
			sqlgraph.From(Table, FieldID),
			sqlgraph.Edge(sqlgraph.M2O, true, ConfigTable, ConfigColumn),
		)
		sqlgraph.HasNeighbors(s, step)
	})
}

// HasConfigWith applies the HasEdge predicate on the "config" edge with a given conditions (other predicates).
func HasConfigWith(preds ...predicate.UpstreamConfig) predicate.UpstreamKeyRateSnapshot {
	return predicate.UpstreamKeyRateSnapshot(func(s *sql.Selector) {
		step := newConfigStep()
		sqlgraph.HasNeighborsWith(s, step, func(s *sql.Selector) {
			for _, p := range preds {
				p(s)
			}
		})
	})
}

