// And groups predicates with the AND operator between them.
func And(predicates ...predicate.UpstreamKeyRateSnapshot) predicate.UpstreamKeyRateSnapshot {
	return predicate.UpstreamKeyRateSnapshot(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.UpstreamKeyRateSnapshot) predicate.UpstreamKeyRateSnapshot {
	return predicate.UpstreamKeyRateSnapshot(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.UpstreamKeyRateSnapshot) predicate.UpstreamKeyRateSnapshot {
	return predicate.UpstreamKeyRateSnapshot(sql.NotPredicates(p))
}
